exports.handler = async (event) => {
    const request = event.Records[0].cf.request;
    const response = event.Records[0].cf.response;
    
    // Only process HTML responses
    const contentType = response.headers['content-type']?.[0]?.value || '';
    if (!contentType.includes('text/html')) {
        return response;
    }
    
    // Parse custom headers for injection points
    const injectionPoints = parseCustomHeaders(request.headers);
    
    // Get HTML body
    let body = '';
    if (response.body) {
        if (response.body.encoding === 'base64') {
            body = Buffer.from(response.body.value, 'base64').toString('utf-8');
        } else {
            body = response.body.value;
        }
    }
    
    // Inject personalized content
    if (injectionPoints && Object.keys(injectionPoints).length > 0) {
        body = injectContent(body, injectionPoints);
    }
    
    // Update response body
    response.body = {
        value: body,
        encoding: 'utf-8'
    };
    
    return response;
};

function parseCustomHeaders(headers) {
    const injectionPoints = {};
    
    // Extract injection points from custom headers
    for (const [key, value] of Object.entries(headers)) {
        if (key.toLowerCase().startsWith('x-inject-')) {
            const injectionPoint = key.toLowerCase().substring(11); // Remove 'x-inject-'
            const content = value[0]?.value || '';
            
            // Validate injection point name (alphanumeric and underscore only)
            if (/^[a-zA-Z0-9_]+$/.test(injectionPoint)) {
                injectionPoints[injectionPoint] = content;
            }
        }
    }
    
    return injectionPoints;
}

function injectContent(html, injectionPoints) {
    // Sanitize injection points to prevent XSS
    const sanitizedPoints = {};
    for (const [key, value] of Object.entries(injectionPoints)) {
        sanitizedPoints[key] = sanitizeHtml(value);
    }
    
    // Inject content at specified locations
    let result = html;
    
    for (const [point, content] of Object.entries(sanitizedPoints)) {
        // Create a safe regex pattern for injection point
        const escapedPoint = escapeRegExp(point);
        const injectionRegex = new RegExp(`<!--\\s*INJECT\\s+${escapedPoint}\\s*-->`, 'g');
        
        // Replace all occurrences
        result = result.replace(injectionRegex, content);
    }
    
    return result;
}

function sanitizeHtml(html) {
    // Basic HTML sanitization to prevent XSS
    return html
        .replace(/</g, '&lt;')
        .replace(/>/g, '&gt;')
        .replace(/"/g, '&quot;')
        .replace(/'/g, '&#x27;');
}

function escapeRegExp(string) {
    return string.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
}